const raw = $input.first().json;
const body = raw.body ?? raw;
const { template, envios, schools, pixelBase, varsPorEnvio = {} } = body;
const appUrl = pixelBase.replace('/api/pixel', '');

return envios.map(envio => {
  const manual = varsPorEnvio[envio.id] ?? null;
  const fromSchool = schools[envio.sigla] ?? null;
  const escola = manual
    ? { nome: manual.nome ?? '', cre: manual.cre ?? '', bairro: manual.bairro ?? '', endereco: manual.endereco ?? '' }
    : (fromSchool ?? { nome: '', cre: '', bairro: '', endereco: '' });
  return {
    json: {
      envioId: envio.id,
      email: envio.email,
      sigla: envio.sigla,
      assunto: template.assunto,
      html: template.html,
      pixelBase,
      appUrl,
      escola,
      varsExtra: manual ?? {}
    }
  };
});

const item = $input.item.json;
let html = item.html;

// Substituir todas as variáveis {{x}} — prioriza varsExtra (modo manual), depois escola
const vars = {
  nome: item.escola.nome,
  cre: item.escola.cre,
  bairro: item.escola.bairro,
  sigla: item.sigla,
  endereco: item.escola.endereco,
  ...(item.varsExtra ?? {})
};
html = html.replace(/\{\{(\w+)\}\}/g, (_, k) => vars[k] ?? '');

// Pixel de abertura
const pixel = `<img src="${item.pixelBase}/${item.envioId}.gif" width="1" height="1" alt="" style="display:none" />`;
html = html.includes('</body>') ? html.replace('</body>', pixel + '</body>') : html + pixel;

// Anti-dark-mode: injetar meta color-scheme
const metaTag = '<meta name="color-scheme" content="light only"><meta name="supported-color-schemes" content="light"><style>:root{color-scheme:light only;supported-color-schemes:light;}</style>';
if (!/<html[\s>]/i.test(html)) {
  html = `<!DOCTYPE html><html><head><meta charset="utf-8">${metaTag}</head><body>${html}</body></html>`;
} else if (!/<meta[^>]+name=["']color-scheme/i.test(html)) {
  html = html.replace(/<head[^>]*>/i, m => m + metaTag);
}

return { json: { ...item, htmlFinal: html } };
